from math import sqrt


def sum_of_divisors(n: int) -> int:
    if n <= 1: return 0
    total = 1
    for i in range(2, int(sqrt(n)) + 1):
        if n % i == 0:
            if i * i == n: total += i
            else: total += i + n // i
    return total


def solution(n: int = 10000) -> int:
    total = 0
    for i in range(1, n):
        b = sum_of_divisors(i)
        if b != i and b < n and sum_of_divisors(b) == i:
            total += i
    return total


if __name__ == "__main__":
    print(solution(10000))

