def solution(n: int = 10000) -> int:
    """
    Optimized amicable number search using a sieve-like approach to pre-calculate divisor sums.
    """
    div_sums = [0] * n
    for i in range(1, n // 2 + 1):
        for j in range(2 * i, n, i):
            div_sums[j] += i

    amicable_sum = 0
    for a in range(1, n):
        b = div_sums[a]
        if b < n and a != b and div_sums[b] == a:
            amicable_sum += a

    return amicable_sum


if __name__ == "__main__":
    print(solution(10000))
